package com.museumheist.game.entity;
import android.graphics.RectF;
public class Door { private final RectF bounds; private final String keyCode,label; private final int color; private final boolean initiallyOpen; private boolean open; public Door(RectF b,String code,String label,int color){this(b,code,label,color,false);} public Door(RectF b,String code,String label,int color,boolean open){bounds=new RectF(b);keyCode=code;this.label=label;this.color=color;initiallyOpen=open;this.open=open;} public RectF getBounds(){return bounds;} public String getKeyCode(){return keyCode;} public String getLabel(){return label;} public int getColor(){return color;} public boolean isOpen(){return open;} public boolean isBlocking(){return !open;} public void toggle(){open=!open;} public void reset(){open=initiallyOpen;} }
